'use client'

import { createContext, type ReactNode } from 'react'
import { useSignals } from '@cascivo/core'
import { usePopover, type UsePopoverOptions, type UsePopoverReturn } from './use-popover'
import styles from './popover.module.css'

const PopoverContext = createContext<UsePopoverReturn | null>(null)

export interface PopoverProps extends UsePopoverOptions {
  children: ReactNode
}

export function Popover({ children, ...options }: PopoverProps) {
  const popover = usePopover(options)
  return <PopoverContext.Provider value={popover}>{children}</PopoverContext.Provider>
}

export interface PopoverTriggerProps {
  children: ReactNode
  asChild?: boolean
}

export function PopoverTrigger({ children }: PopoverTriggerProps) {
  useSignals()
  return (
    <PopoverContext.Consumer>
      {(ctx) => {
        if (!ctx) throw new Error('PopoverTrigger must be used inside <Popover>')
        const { triggerRef, toggle, anchorName, isOpen } = ctx
        return (
          <button
            ref={triggerRef as React.RefObject<HTMLButtonElement>}
            type="button"
            aria-expanded={isOpen.value}
            aria-haspopup="dialog"
            style={{ anchorName } as React.CSSProperties}
            onClick={toggle}
            className={styles.trigger}
          >
            {children}
          </button>
        )
      }}
    </PopoverContext.Consumer>
  )
}

export interface PopoverContentProps {
  children: ReactNode
  className?: string
}

export function PopoverContent({ children, className }: PopoverContentProps) {
  useSignals()
  return (
    <PopoverContext.Consumer>
      {(ctx) => {
        if (!ctx) throw new Error('PopoverContent must be used inside <Popover>')
        const { popoverRef, anchorName, isOpen } = ctx
        return (
          <div
            ref={popoverRef as React.RefObject<HTMLDivElement>}
            // eslint-disable-next-line @typescript-eslint/ban-ts-comment
            // @ts-ignore — popover is a valid HTML attribute not yet in React types
            popover="auto"
            role="dialog"
            data-state={isOpen.value ? 'open' : 'closed'}
            style={{ positionAnchor: anchorName } as React.CSSProperties}
            className={[styles.content, className].filter(Boolean).join(' ')}
          >
            {children}
          </div>
        )
      }}
    </PopoverContext.Consumer>
  )
}

import { useRef } from 'react'
import { useSignal, useSignalEffect } from '@cascivo/core'
import type { Signal } from '@cascivo/core'

let anchorCounter = 0

export interface UsePopoverOptions {
  open?: boolean
  onOpenChange?: (open: boolean) => void
  placement?: 'top' | 'bottom' | 'left' | 'right'
  offset?: number
}

export interface UsePopoverReturn {
  triggerRef: React.RefObject<HTMLElement | null>
  popoverRef: React.RefObject<HTMLElement | null>
  isOpen: Signal<boolean>
  anchorName: string
  open: () => void
  close: () => void
  toggle: () => void
}

const supportsAnchor =
  typeof CSS !== 'undefined' &&
  typeof CSS.supports === 'function' &&
  CSS.supports('anchor-name: --cascivo-a')

export function usePopover(options: UsePopoverOptions = {}): UsePopoverReturn {
  const anchorName = useRef(`--cascivo-popover-${++anchorCounter}`).current
  const triggerRef = useRef<HTMLElement>(null)
  const popoverRef = useRef<HTMLElement>(null)
  const isOpen = useSignal(options.open ?? false)

  // Sync controlled prop into signal during render
  if (options.open !== undefined) {
    isOpen.value = options.open
  }

  const onOpenChangeRef = useRef(options.onOpenChange)
  onOpenChangeRef.current = options.onOpenChange

  const placementRef = useRef(options.placement)
  placementRef.current = options.placement

  const offsetRef = useRef(options.offset)
  offsetRef.current = options.offset

  useSignalEffect(() => {
    const open = isOpen.value
    onOpenChangeRef.current?.(open)

    const popover = popoverRef.current
    if (!popover) return

    if (open) {
      try {
        popover.showPopover()
      } catch {
        // Already shown or browser doesn't support Popover API
      }
    } else {
      try {
        popover.hidePopover()
      } catch {
        // Already hidden
      }
    }

    // Fallback positioning when CSS Anchor Positioning is unsupported
    if (!supportsAnchor && open) {
      const trigger = triggerRef.current
      if (!trigger) return
      const rect = trigger.getBoundingClientRect()
      const placement = placementRef.current ?? 'bottom'
      const offset = offsetRef.current ?? 4
      if (placement === 'bottom') {
        popover.style.top = `${rect.bottom + offset + window.scrollY}px`
        popover.style.left = `${rect.left + window.scrollX}px`
      } else if (placement === 'top') {
        popover.style.top = `${rect.top - offset + window.scrollY}px`
        popover.style.left = `${rect.left + window.scrollX}px`
        popover.style.transform = 'translateY(-100%)'
      } else if (placement === 'left') {
        popover.style.top = `${rect.top + window.scrollY}px`
        popover.style.left = `${rect.left - offset + window.scrollX}px`
        popover.style.transform = 'translateX(-100%)'
      } else if (placement === 'right') {
        popover.style.top = `${rect.top + window.scrollY}px`
        popover.style.left = `${rect.right + offset + window.scrollX}px`
      }
    }
  })

  // Listen for popover hide (light-dismiss clicks)
  useSignalEffect(() => {
    const popover = popoverRef.current
    if (!popover) return
    const handler = (e: Event) => {
      const toggleEvent = e as ToggleEvent
      if (toggleEvent.newState === 'closed') {
        isOpen.value = false
      }
    }
    popover.addEventListener('toggle', handler)
    return () => popover.removeEventListener('toggle', handler)
  })

  return {
    triggerRef,
    popoverRef,
    isOpen,
    anchorName,
    open: () => {
      isOpen.value = true
    },
    close: () => {
      isOpen.value = false
    },
    toggle: () => {
      isOpen.value = !isOpen.value
    },
  }
}

@layer cascivo.component {
  .trigger {
    /* Trigger inherits button styles from the consuming component */
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-block-size: 1.5rem; /* 24px — WCAG 2.5.8 target size */
    min-inline-size: 1.5rem;
  }

  .content {
    position: fixed;
    inset: auto;
    margin: 0;
    padding: var(--cascivo-space-3);
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-md);

    /* CSS Anchor Positioning — supported browsers */
    @supports (anchor-name: --a) {
      position-try-fallbacks:
        flip-block,
        flip-inline,
        flip-block flip-inline;
      inset-block-start: anchor(end);
      inset-inline-start: anchor(start);
    }

    /* Enter animation */
    opacity: 1;
    translate: 0 0;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter),
      display var(--cascivo-motion-enter) allow-discrete,
      overlay var(--cascivo-motion-enter) allow-discrete;

    @starting-style {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
    }

    &[data-state='closed'] {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
      transition:
        opacity var(--cascivo-motion-exit),
        translate var(--cascivo-motion-exit),
        display var(--cascivo-motion-exit) allow-discrete,
        overlay var(--cascivo-motion-exit) allow-discrete;
    }
  }
}
